import express from "express";
import { UserController } from "./src/controllers/user.controller.js";
import { CreateUserService } from "./src/services/create.user.service.js";
import { UserRepository } from "./src/repositories/user.repository.js";

const userRepository = new UserRepository();
const createUserService = new CreateUserService(userRepository);
const userController = new UserController(createUserService);

handle(request, response) {
  const { body } = request;

  try {
    const result = this.createUserService.execute(body);
    return response.json(result);
  }
}

execute(data) {
  if (!data.username) {
    throw new Error("Username é obrigatório");
  }
}

const existUser = this.userRepository.findByUsername(data.username);

if (existUser) {
  throw new Error("Usuário já cadastrado!");
}

findByUsername(username) {
  const userExists = this.users.find((user) => user.username === username);
  return userExists;
}

save(user) {
  const id = Math.random().toString();
  const userWithId = { ...user, id };
  this.users.push(userWithId);
  return userWithId;
}
